const fs = require('fs');
const path = require('path');
const base = process.cwd();

const files = {"src/lib/types.ts":"","src/app/api/admin/google-sync/route.ts":"","src/app/api/admin/contractors/route.ts":"","src/app/admin/contractors/page.tsx":"","src/app/admin/contractors/add/page.tsx":"","src/app/contractors/[slug]/page.tsx":"","supabase/migrations/006_google_reviews.sql":""};

for (const [filePath, b64] of Object.entries(files)) {
  const fullPath = path.join(base, filePath);
  const dir = path.dirname(fullPath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  const content = Buffer.from(b64, 'base64').toString('utf-8');
  fs.writeFileSync(fullPath, content);
  console.log('✓ ' + filePath);
}

console.log('\nDone! All files patched.');
console.log('Run: git add . && git commit -m "Google Reviews integration" && git push');
